%[text] ## `Beta(1,1); Independent(Many):`
%[text] # `Instead of Bits/Frame,` 
%[text] ## `Convert to Bits/nSteps:`
%[text] # `Get Rid of Central Panel:`
%[text] `Longer Trajectories, Longer Segments:`
%[text] `Try One Segment`
%cd("C:\Users\zacha\ASU Dropbox\Zachary Hendrix\Likelihood Preservation")
cd("A:/ASU Dropbox\Zachary Hendrix\Likelihood Preservation")

%%\
%Configure

%% Reset & Specify MATLAB Path:
restoredefaultpath;    clear;    close all;    clc;    addpath(genpath(fileparts(mfilename('fullpath'))))
%% Set Plotting Preferences:
set(groot, "DefaultAxesTickLabelInterpreter",'LaTeX', "DefaultTextInterpreter",'LaTeX', "DefaultLegendInterpreter",'LaTeX');
set(groot, "DefaultFigureColor",'w',                  "DefaultAxesColor",'w')
%% Fix Pseudorandom Number Generator:
%%%%%%%%%%%%%%%%%%%%%%
Pseudorandom.Seed = 9;%11;%10;%99;    
%%%%%%%%%%%%%%%%%%%%%%
Pseudorandom.Generator = "Twister";    rng(Pseudorandom.Seed, Pseudorandom.Generator)
%%\
%[text] ### `Set HMM(2) Parameters:` $\\mathbf{\\vartheta}=\\{\\pi\_{\\sigma\_{1}\\to\\sigma\_{2}},\\pi\_{\\sigma\_{2}\\to\\sigma\_{1}}\\}$
%GT.p = 0.10; % Pr(σ1 -> σ2)
%GT.q = GT.p; % Pr(σ2 -> σ1)

GT.p = betarnd(1,1); % Pr(σ1 -> σ2)
GT.q = betarnd(1,1)  % GT.p; % Pr(σ2 -> σ1)
%[text]  `Transition Matrix` $\\mathbf{\\Pi}\n\\equiv\\{\\mathbf{\\pi}\_{\\sigma\_{m}}\\}\n\\equiv\\{\\pi\_{\\sigma\_{m}\\to\\sigma\_{m^{\\prime}}}\\}\n\\in\[0,1\]^{M \\times M}$`:`
GT.TransitionMatrix       = [1-GT.p, GT.p; GT.q, 1-GT.q];
%[text]  `Stationary Distribution` $\\mathbf{\\varrho}=\\mathbf{\\varrho}\\mathbf{\\Pi}$`:` 
GT.StationaryDistribution = [GT.q, GT.p] / (GT.p + GT.q);
%[text] ####  `Emission Model` $\\mathbb{P}(w\_{n}\\,|\\,s\_{n},\\phi\_{s\_{n}})$`:`
GT.Mean              = [1  2]           ;
GT.Variance          = 0.005            ;
GT.StandardDeviation = sqrt(GT.Variance);

EmissionModel = @(w,S) pdfNormal(w, GT.Mean(S), GT.Variance);
%[text] ### `Set Data Acquisition Parameters:`
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
Long.nTimes = 100; % 10000 
            %  1000;
%1000;
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
nSegments   = ...2;%Long.nTimes / 2;%4;%25%;
...              Long.nTimes / 25;
              Long.nTimes / 20;
Many.nTimes = Long.nTimes / nSegments;
%[text] # `Simulation:`
%[text] ####  `Initialize:`
Many.S = cell(nSegments,1);  
Many.w = cell(nSegments,1);
Long.S = zeros(Long.nTimes,1);
Long.w = zeros(Long.nTimes,1);

[Long.S, Long.w] = simulateHMM(Long.nTimes, GT.StationaryDistribution, GT.TransitionMatrix, GT.Mean, GT.StandardDeviation);
for  nSegment  = 1 :       nSegments
  if nSegment == 1 ; Times{nSegment} = 1 : Many.nTimes                           ;
  else             ; Times{nSegment} = Times{nSegment-1}(end) + (1 : Many.nTimes);
  end

%%%%%     %%%%%     %%%%%     %%%%%     %%%%%
%    Many.S{nSegment} = Long.S(Times{nSegment});
%    Many.w{nSegment} = Long.w(Times{nSegment});
%% INDEPENDENT RUNS:
    [Many.S{nSegment}, Many.w{nSegment}] = simulateHMM(Many.nTimes, GT.StationaryDistribution, GT.TransitionMatrix, GT.Mean, GT.StandardDeviation);
%%%%%     %%%%%     %%%%%     %%%%%     %%%%%

end
%[text] # `Analysis:`
%[text] ####  `Grid:`
%gridDelta = 
epsilon  = 10^(-4);
gridMin  = 0 + epsilon;%0.05; %min([min(GT.p)  min(GT.q)]) * (1 - gridDelta) 
gridMax  = 1 - epsilon;%0.15; %max([max(GT.p)  max(GT.q)]) * (1 + gridDelta)

nLattice = 500;%100;%350;
Grid.p = linspace(gridMin, gridMax, nLattice);
Grid.q = linspace(gridMin, gridMax, nLattice);
%[text] ####  `Precompute Emissions:`
nStates = numel(GT.Mean);
BLong  = getEmissionMatrix(Long.w, EmissionModel, nStates);
BMany  = cell(nSegments,1);
for nSegment = 1 : nSegments, BMany{nSegment} = getEmissionMatrix(Many.w{nSegment}, EmissionModel, nStates); end
%[text] ## `Likelihood:`
ZERO                        = zeros(numel(Grid.p), numel(Grid.q));
Long.logLikelihood          = ZERO;
Long.logLikelihoodRestarted = ZERO;
Many.logLikelihood          = ZERO;

useParallel = ...false;
              ~isempty(ver("Parallel"));
if useParallel
    Pool = gcp("NoCreate");
    if isempty(Pool), parpool; end
end

startSegment = 1 : Many.nTimes : Long.nTimes;
endSegment   = startSegment + Many.nTimes - 1;

longLogL        = ZERO;
LL_long_restart = ZERO;
LL_many         = ZERO;

if useParallel
    pGrid           = Grid.p;
    qGrid           = Grid.q;
    BLong_local     = BLong;
    BMany_local     = BMany;
    segStarts_local = startSegment;
    segEnds_local   = endSegment;

    parfor pIndex = 1:numel(pGrid)
        p = pGrid(pIndex);

        rowL        = zeros(1, numel(qGrid));
        rowLrestart = zeros(1, numel(qGrid));
        rowM        = zeros(1, numel(qGrid));

        for qIndex = 1:numel(qGrid)
            q = qGrid(qIndex);

            TransitionMatrix       = [1-p, p; q, 1-q];
            StationaryDistribution = [q, p] / (p + q);

            % Equation (9): one contiguous long trajectory
            rowL(qIndex) = getMarginalLikelihood(BLong_local, StationaryDistribution, TransitionMatrix);

            % Equation (10): same long trajectory, but restarted at segment boundaries
            rowLrestart(qIndex) = getSegmentedMarginalLikelihood(BLong_local, segStarts_local, segEnds_local, StationaryDistribution, TransitionMatrix);

            % Equation (10): many independent short trajectories
            rowM(qIndex) = logLikEq10_cell_preB(BMany_local, StationaryDistribution, TransitionMatrix);
        end

        longLogL(pIndex,:)        = rowL;
        LL_long_restart(pIndex,:) = rowLrestart;
        LL_many(pIndex,:)         = rowM;
    end
else
    for pIndex = 1:numel(Grid.p)
        p = Grid.p(pIndex);

        for qIndex = 1:numel(Grid.q)
            q = Grid.q(qIndex);

            TransitionMatrix       = [1-p, p; q, 1-q];
            StationaryDistribution = [q, p] / (p + q);

            % Equation (9): one contiguous long trajectory
            longLogL(pIndex,qIndex) = getMarginalLikelihood(BLong, StationaryDistribution, TransitionMatrix);

            % Equation (10): same long trajectory, but restarted at segment boundaries
            LL_long_restart(pIndex,qIndex) = getSegmentedMarginalLikelihood(BLong, startSegment, endSegment, StationaryDistribution, TransitionMatrix);

            % Equation (10): many independent short trajectories
            LL_many(pIndex,qIndex) = logLikEq10_cell_preB(BMany, StationaryDistribution, TransitionMatrix);
        end
    end
end

Long.logLikelihood          = longLogL;
Long.logLikelihoodRestarted = LL_long_restart;
Many.logLikelihood          = LL_many;
%[text] #### `Prior` $\\mathbb{P}(\\mathbf{\\vartheta})$`:` $\\mathbb{B}(1,1)$ `(Uniform).`
Shapes    = [1  1];

logPriorP = (Shapes(1)-1)*log(Grid.p) + (Shapes(2)-1)*log1p(-Grid.p) - betaln(Shapes(1),Shapes(2));
logPriorQ = (Shapes(1)-1)*log(Grid.q) + (Shapes(2)-1)*log1p(-Grid.q) - betaln(Shapes(1),Shapes(2));

Prior.p = betapdf(Grid.p, Shapes(1), Shapes(2));  Prior.p = Prior.p / trapz(Grid.p, Prior.p);
Prior.q = betapdf(Grid.q, Shapes(1), Shapes(2));  Prior.q = Prior.q / trapz(Grid.q, Prior.q);
%[text] #### `Joint Posterior` $\\mathbb{P}(\\mathbf{\\vartheta}\\,|\\,\\mathbf{\\mathit{w}})$`:`
logPostLongRaw = Long.logLikelihood + logPriorP.' + logPriorQ;
logPostLongRestartRaw = Long.logLikelihoodRestarted + logPriorP.' + logPriorQ;
logPostManyRaw = Many.logLikelihood + logPriorP.' + logPriorQ;
%[text] #### `Marginal Posteriors:`
[postLong, ~]        = normalizeLog2D(logPostLongRaw, Grid.p, Grid.q)       ;
[postLongRestart, ~] = normalizeLog2D(logPostLongRestartRaw, Grid.p, Grid.q);
[postMany, ~]        = normalizeLog2D(logPostManyRaw, Grid.p, Grid.q)       ;
%[text] # `Information:` $\\int{\\mathrm{d}\\bf{\\vartheta}}\\:\n\\left\[\n{\\mathbb{P}(\\bf{\\vartheta}\\,|\\,\\bf{\\it{w}})}\n\\times\n\\log\_{2}\n\\frac{\\mathbb{P}(\\bf{\\vartheta}\\,|\\,\\bf{\\it{w}})}\n{\\mathbb{P}(\\bf{\\vartheta})}\n\\right\]$.
%[text] `Bit Flux Information:` $I=\\sum {p\\log{p}}$.
%% -------------------- Information about theta ----------------------------
% Best metric for this manuscript:
%   realized information gain from prior to posterior, in bits
%   I(D) = D_KL[ P(theta|D) || P(theta) ].
%
% This uses the FULL 2D posterior over (p,q), not the 1D marginals.

Prior.joint = Prior.p(:) * Prior.q(:).';   % nP x nQ, normalized on the grid

Info.Long.bits        = KullbackLeiblerDivergence(postLong,        Prior.joint, Grid.p, Grid.q);
Info.Many.bits        = KullbackLeiblerDivergence(postMany,        Prior.joint, Grid.p, Grid.q);
Info.LongRestart.bits = KullbackLeiblerDivergence(postLongRestart, Prior.joint, Grid.p, Grid.q);

% Choose your time unit:
dt = 1;   % time per frame; set dt = frame interval in seconds if needed

% Two sensible normalizations:
Info.Long.bitsPerObservation        = Info.Long.bits        / Long.nTimes;
Info.Many.bitsPerObservation        = Info.Many.bits        / Long.nTimes;
Info.LongRestart.bitsPerObservation = Info.LongRestart.bits / Long.nTimes;

Info.Long.bitsPerTime        = Info.Long.bits        / (Long.nTimes * dt);
Info.Many.bitsPerTime        = Info.Many.bits        / (Long.nTimes * dt);
Info.LongRestart.bitsPerTime = Info.LongRestart.bits / (Long.nTimes * dt);

% "Same information?" -- compare the posterior surfaces directly
Info.JS.Long_vs_Many.bits          = JensenShannonDivergence(postLong,        postMany, Grid.p, Grid.q);
Info.JS.LongRestart_vs_Many.bits   = JensenShannonDivergence(postLongRestart, postMany, Grid.p, Grid.q);
Info.JS.Long_vs_LongRestart.bits   = JensenShannonDivergence(postLong,        postLongRestart, Grid.p, Grid.q);

fprintf('\nInformation gain about theta = (p,q)\n');
fprintf('------------------------------------\n');
fprintf('Long         : %.6f bits   | %.6e bits/frame   | %.6e bits/time\n', Info.Long.bits, Info.Long.bitsPerObservation, Info.Long.bitsPerTime);
fprintf('Many         : %.6f bits   | %.6e bits/frame   | %.6e bits/time\n', Info.Many.bits, Info.Many.bitsPerObservation, Info.Many.bitsPerTime);
fprintf('LongRestart  : %.6f bits   | %.6e bits/frame   | %.6e bits/time\n', Info.LongRestart.bits, Info.LongRestart.bitsPerObservation, Info.LongRestart.bitsPerTime);

fprintf('\nPosterior similarity (Jensen-Shannon divergence)\n');
fprintf('------------------------------------------------\n');
fprintf('JS(Long, Many)              = %.6e bits\n', Info.JS.Long_vs_Many.bits);
fprintf('JS(LongRestart, Many)       = %.6e bits\n', Info.JS.LongRestart_vs_Many.bits);
fprintf('JS(Long, LongRestart)       = %.6e bits\n', Info.JS.Long_vs_LongRestart.bits);
%[text] ####  `Normalization:`
Long.logPosterior.p = trapz(Grid.q, postLong, 2)';  
Long.logPosterior.p = Long.logPosterior.p / trapz(Grid.p, Long.logPosterior.p);
Long.logPosterior.q = trapz(Grid.p, postLong, 1);   
Long.logPosterior.q = Long.logPosterior.q / trapz(Grid.q, Long.logPosterior.q);

Long.logPosteriorRestarted.p = trapz(Grid.q, postLongRestart, 2)';  
Long.logPosteriorRestarted.p = Long.logPosteriorRestarted.p / trapz(Grid.p, Long.logPosteriorRestarted.p);
Long.logPosteriorRestarted.q = trapz(Grid.p, postLongRestart, 1);   
Long.logPosteriorRestarted.q = Long.logPosteriorRestarted.q / trapz(Grid.q, Long.logPosteriorRestarted.q);

Many.logPosterior.p = trapz(Grid.q, postMany, 2)';  
Many.logPosterior.p = Many.logPosterior.p / trapz(Grid.p, Many.logPosterior.p);
Many.logPosterior.q = trapz(Grid.p, postMany, 1);   
Many.logPosterior.q = Many.logPosterior.q / trapz(Grid.q, Many.logPosterior.q);
%[text] ## Summary Statistics:
Summary.Long.p = summarizePosterior(Grid.p, Long.logPosterior.p);
Summary.Long.q = summarizePosterior(Grid.q, Long.logPosterior.q);

Summary.LongRestart.q = summarizePosterior(Grid.q, Long.logPosteriorRestarted.q);
Summary.LongRestart.q = summarizePosterior(Grid.q, Long.logPosteriorRestarted.q);

Summary.Many.p = summarizePosterior(Grid.p, Many.logPosterior.p);
Summary.Many.q = summarizePosterior(Grid.q, Many.logPosterior.q);
%%
