function [States, Observations] = simulateHMM(nTimes, StationaryDistribution, TransitionMatrix, Mean, Std)
    States       = zeros(nTimes,1);
    Observations = zeros(nTimes,1);
    States(1)    = sampleCategorical(StationaryDistribution);
    Observations(1) = normrnd(Mean(States(1)), Std);
    for n = 2 : nTimes
        States(n)       = sampleCategorical(TransitionMatrix(States(n-1),:));
        Observations(n) = normrnd(Mean(States(n)), Std);
    end
end

function Sample = sampleCategorical(Prob)
    C = cumsum(Prob(:)'); 
    Sample = find(rand <= C, 1, "First");
end

function B = getEmissionMatrix(y, EmissionModel, nStates)
    y = y(:); N = numel(y);
    B = zeros(N,nStates);
    for k = 1 : nStates
        B(:,k) = EmissionModel(y,k);
    end
end

function logL = forwardLogLik_preB(B, timeIndex, pi0, TransitionMatrix)
    timeIndex = timeIndex(:).';
    N = size(B,1); 
    nStates = size(B,2);
    deltas = [timeIndex(1)-1, diff(timeIndex)];
    uniqD  = unique(deltas);
    Apow = containers.Map('KeyType','double','ValueType','any');
    for i = 1 : numel(uniqD)
        d = uniqD(i);
        if d == 0
            Apow(d) = eye(nStates);
        else
            Apow(d) = TransitionMatrix^d;
        end
    end
    alpha = pi0(:)'; 
    Csum = 0;
    for n = 1 : N
        alpha = alpha * Apow(deltas(n));
        un    = alpha .* B(n,:);
        c     = sum(un);
        if ~(c > 0) || ~isfinite(c), c = realmin; end
        alpha = un / c;
        Csum  = Csum + log(c);
    end
    logL = Csum;
end

%{
% Restart forward algorithm at specified segment boundaries
function logL = forwardLogLik_segmented_preB(B, segStarts, segEnds, pi0, TransitionMatrix)
    logL = 0;
    for nSegment = 1 : numel(segStarts)
        idx = segStarts(nSegment):segEnds(nSegment);
        logL = logL + forwardLogLik_preB(B(idx,:), 1 : numel(idx), pi0, TransitionMatrix);
    end
end
%}

function [P, logP] = normalizeLog2D(logU, x, y)
    M = max(logU(:));
    U = exp(logU - M);
    Z = trapz(y, trapz(x, U, 1));
    if Z <= 0 || ~isfinite(Z)
        sU = sum(U(:));
        if sU <= 0 || ~isfinite(sU)
            P    = ones(size(U))/numel(U);
            logP = -log(numel(U)) + zeros(size(U));
        else
            P    = U / sU;
            logP = logU - (log(sU) + M);
        end
    else
        P    = U / Z;
        logP = logU - (log(Z) + M);
    end
end

function Summary = summarizePosterior(x, PDF)
    PDF = max(PDF(:)', 0);
    Z   = trapz(x, PDF);
    if Z <= 0 || ~isfinite(Z)
        Summary.Mean = NaN; Summary.HPD = [NaN NaN]; return;
    end
    PDF = PDF / Z;
    CDF = cumtrapz(x, PDF); CDF = CDF / CDF(end);
    [CDF, Index] = unique(CDF,'stable');  xU = x(Index);
    if CDF(1)  > 0, CDF = [0; CDF];   xU = [xU(1); xU]; end
    if CDF(end)< 1, CDF = [CDF; 1];   xU = [xU; xU(end)]; end
    Summary.Mean = trapz(x, x.*PDF);
    Summary.HPD  = [interp1(CDF, xU, 0.025, "linear"), interp1(CDF, xU, 0.975, "linear")];
end

function y = pdfNormal(w, mu, varg)
    sig2 = max(varg, realmin);
    y = (1./sqrt(2*pi*sig2)) .* exp(-1/2*((w - mu).^2)./sig2);
end

